// --- Domain equalities (each post equals pre, hence post1 == post2 transitively).
assert(post1_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post2_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post1_self_.container_dom() == pre_self_.container_dom());
assert(post2_self_.container_dom() == pre_self_.container_dom());
assert(post1_self_.thread_dom() == pre_self_.thread_dom());
assert(post2_self_.thread_dom() == pre_self_.thread_dom());
assert(post1_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post2_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post1_self_.page_closure() =~= pre_self_.page_closure());
assert(post2_self_.page_closure() =~= pre_self_.page_closure());
assert(post1_self_.endpoint_dom() == post2_self_.endpoint_dom());
assert(post1_self_.container_dom() == post2_self_.container_dom());
assert(post1_self_.thread_dom() == post2_self_.thread_dom());
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
assert(post1_self_.page_closure() =~= post2_self_.page_closure());

// --- proc_dom forall: both runs equal pre on every p_ptr, hence equal to each other.
// Triggers on the post-projections so this forall fires when det_<f>_equal asks
// for `post1.get_proc(p_ptr)` / `post2.get_proc(p_ptr)`.
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr)]
    #![trigger post2_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr) implies
    post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr) by {
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
};

// --- container_dom forall (all containers except the owning container).
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr)]
    #![trigger post2_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr)
        && c_ptr != pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container implies
    post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr) by {
    assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
};

// --- container.subtree_set agrees for every container in the domain.
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr)]
    #![trigger post2_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr) implies
    post1_self_.get_container(c_ptr).subtree_set
        =~= post2_self_.get_container(c_ptr).subtree_set by {
    assert(post1_self_.get_container(c_ptr).subtree_set
        =~= pre_self_.get_container(c_ptr).subtree_set);
    assert(post2_self_.get_container(c_ptr).subtree_set
        =~= pre_self_.get_container(c_ptr).subtree_set);
};

// --- thread_dom forall (all threads except the head of the endpoint's queue).
// Triggers on post-projections to match how det_<f>_equal will probe.
assert forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.get_thread(t_ptr)]
    #![trigger post2_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr)
        && t_ptr != pre_self_.get_endpoint(endpoint_ptr).queue@[0] implies
    post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {
    assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
    assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
};

// --- thread.endpoint_descriptors agrees for every thread in the domain (including head).
assert forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.get_thread(t_ptr)]
    #![trigger post2_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) implies
    post1_self_.get_thread(t_ptr).endpoint_descriptors
        =~= post2_self_.get_thread(t_ptr).endpoint_descriptors by {
    assert(pre_self_.get_thread(t_ptr).endpoint_descriptors
        =~= post1_self_.get_thread(t_ptr).endpoint_descriptors);
    assert(pre_self_.get_thread(t_ptr).endpoint_descriptors
        =~= post2_self_.get_thread(t_ptr).endpoint_descriptors);
};

// --- endpoint_dom forall (all endpoints except endpoint_ptr).
// The ensures phrases the antecedent over post_self_.endpoint_dom(); use that
// form here too, but the actual domain coincides with pre's.
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr)]
    #![trigger post2_self_.get_endpoint(e_ptr)]
    pre_self_.endpoint_dom().contains(e_ptr) && e_ptr != endpoint_ptr implies
    post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr) by {
    assert(post1_self_.endpoint_dom().contains(e_ptr));
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
};

// --- endpoint.owning_container agrees for every endpoint in the domain.
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr)]
    #![trigger post2_self_.get_endpoint(e_ptr)]
    pre_self_.endpoint_dom().contains(e_ptr) implies
    post1_self_.get_endpoint(e_ptr).owning_container
        =~= post2_self_.get_endpoint(e_ptr).owning_container by {
    assert(post1_self_.endpoint_dom().contains(e_ptr));
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr).owning_container
        =~= post1_self_.get_endpoint(e_ptr).owning_container);
    assert(pre_self_.get_endpoint(e_ptr).owning_container
        =~= post2_self_.get_endpoint(e_ptr).owning_container);
};

// --- Pinned per-projection equalities at the head thread.
assert(post1_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).endpoint_descriptors
    =~= pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).endpoint_descriptors);
assert(post2_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).endpoint_descriptors
    =~= pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).endpoint_descriptors);
assert(post1_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).endpoint_descriptors
    =~= post2_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).endpoint_descriptors);

