    =~= pre_self_.get_container(pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container).owned_procs);
assert(post1_self_.get_container(pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container).owned_procs
    =~= post2_self_.get_container(pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container).owned_procs);

assert(post1_self_.get_container(pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container).owned_threads
    =~= pre_self_.get_container(pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container).owned_threads);
assert(post2_self_.get_container(pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container).owned_threads
    =~= pre_self_.get_container(pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container).owned_threads);
assert(post1_self_.get_container(pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container).owned_threads
