    =~= pre_self_.get_container(pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container).children);
assert(post1_self_.get_container(pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container).children
    =~= post2_self_.get_container(pre_self_.get_thread(pre_self_.get_endpoint(endpoint_ptr).queue@[0]).owning_container).children);

// --- Pinned per-projection equalities at endpoint_ptr.
assert(post1_self_.get_endpoint(endpoint_ptr).queue@
    == pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1));
